#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        if (N == 1) {
            printf("1 1\n");
        } else {
            long long numerator = 1;
            long long denominator = 1;
            for (int i = 0; i < N; i++) {
                numerator *= 10;
                denominator *= 10;
            }
            if (N % 2 == 0) {
                for (int i = 0; i < N / 2; i++) {
                    numerator *= 9;
                }
            } else {
                for (int i = 0; i < (N + 1) / 2; i++) {
                    numerator *= 9;
                }
            }
            printf("%lld %lld\n", numerator, denominator);
        }
    }
    return 0;
}

